const msg = $input.first().json.message?.text || '';
const chatId = $input.first().json.message?.chat?.id;

// Wyekstrahuj NIP (10 cyfr, opcjonalnie z myślnikami)
const nipMatch = msg.replace(/[\s\-]/g, '').match(/\d{10}/);
const nip = nipMatch ? nipMatch[0] : null;

if (!nip) {
  return [{ json: { error: 'Brak NIP', chatId, msg } }];
}

return [{ json: { nip, chatId } }];

const nip = $('Wyekstrahuj NIP').first().json.nip;
const bialaLista = $('API Biała Lista VAT (MF)').first().json;
const krs = $('API KRS (MS)').first().json;

// Biała Lista
const podmiot = bialaLista.result?.subject || bialaLista.result?.subjects?.[0] || {};
const statusVAT = podmiot.statusVat || 'Nieznany';
const czynnyVAT = statusVAT === 'Czynny';
const nazwaFirmy = podmiot.name || podmiot.firma || 'Nieznana';
const numerKRS = podmiot.krs || '';
const rachunkiBankowe = podmiot.accountNumbers || [];
const dataRejestracji = podmiot.registrationLegalDate || podmiot.residenceAddressData?.regon || '';

// Sygnały ryzyka
const ryzyka = [];
const zalety = [];

if (czynnyVAT) {
  zalety.push('✅ Czynny podatnik VAT (Biała Lista)');
} else {
  ryzyka.push('🚨 NIE jest czynnym podatnikiem VAT!');
}

if (rachunkiBankowe.length > 0) {
  zalety.push(`✅ ${rachunkiBankowe.length} rachunek(ów) bankowych na Białej Liście`);
} else {
  ryzyka.push('⚠️ Brak rachunków bankowych na Białej Liście');
}

if (podmiot.registrationDenialDate) {
  ryzyka.push(`🚨 Data wykreślenia: ${podmiot.registrationDenialDate}`);
}

// Ocena ryzyka
let poziomRyzyka, kolorEmoji;
if (ryzyka.length === 0) {
  poziomRyzyka = 'NISKIE'; kolorEmoji = '🟢';
} else if (ryzyka.filter(r => r.includes('🚨')).length > 0) {
  poziomRyzyka = 'WYSOKIE'; kolorEmoji = '🔴';
} else {
  poziomRyzyka = 'ŚREDNIE'; kolorEmoji = '🟡';
}

const raport = {
  nip,
  nazwaFirmy,
  statusVAT,
  numerKRS,
  rachunki: rachunkiBankowe.slice(0, 3).join(', ') || 'Brak danych',
  ryzyka,
  zalety,
  poziomRyzyka,
  kolorEmoji,
  dataWeryfikacji: new Date().toLocaleDateString('pl-PL')
};

return [{ json: { raport, chatId: $('Wyekstrahuj NIP').first().json.chatId } }];

