const raport = $('Analizuj dane i oceń ryzyko').first().json.raport;
const uzasadnienie = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '';

const msg = `${raport.kolorEmoji} *Raport Weryfikacji Kontrahenta*

*Firma:* ${raport.nazwaFirmy}
*NIP:* \`${raport.nip}\`
*Status VAT:* ${raport.statusVAT}
*Ryzyko:* *${raport.poziomRyzyka}* ${raport.kolorEmoji}

${raport.zalety.length ? '*✅ Pozytywne sygnały:*\n' + raport.zalety.join('\n') : ''}
${raport.ryzyka.length ? '\n*⚠️ Ryzyka:*\n' + raport.ryzyka.join('\n') : ''}

*Rachunki bankowe (Biała Lista):*
${raport.rachunki || 'Brak danych'}

*📋 Werdykt:*
${uzasadnienie}

_Weryfikacja: ${raport.dataWeryfikacji}_`;

return [{ json: { msg, chatId: $('Analizuj dane i oceń ryzyko').first().json.chatId } }];
